import okhttp3.*

class HttpClient {
    private val client = OkHttpClient()

    fun sendRequest(url: String) {
        val request = Request.Builder().url(url).build()
        
        // execute the request and get a response using enqueue method which is non-blocking 
        client.newCall(request).enqueue(object : Callback {
            override fun onResponse(call: Call, response: Response) {
                val responseBody = response.body()?.string()
                // Handle the server's response here
                println("Server responded with: $responseBody")
            }
            
            override fun onFailure(call: Call, e: IOException) {
                println("Failed to get a response from server: ${e.message}")
            }
        })
    }
}